13	func TestClientFromEnvironment(t *testing.T) {
14		type testCase struct {
15			value  string
16			expect string
17			err    error
18		}
19	
20		testCases := map[string]*testCase{
21			"empty":                      {value: "", expect: "http://127.0.0.1:11434"},
22			"only address":               {value: "1.2.3.4", expect: "http://1.2.3.4:11434"},
23			"only port":                  {value: ":1234", expect: "http://:1234"},
24			"address and port":           {value: "1.2.3.4:1234", expect: "http://1.2.3.4:1234"},
25			"scheme http and address":    {value: "http://1.2.3.4", expect: "http://1.2.3.4:80"},
26			"scheme https and address":   {value: "https://1.2.3.4", expect: "https://1.2.3.4:443"},
27			"scheme, address, and port":  {value: "https://1.2.3.4:1234", expect: "https://1.2.3.4:1234"},
28			"hostname":                   {value: "example.com", expect: "http://example.com:11434"},
29			"hostname and port":          {value: "example.com:1234", expect: "http://example.com:1234"},
30			"scheme http and hostname":   {value: "http://example.com", expect: "http://example.com:80"},
31			"scheme https and hostname":  {value: "https://example.com", expect: "https://example.com:443"},
32			"scheme, hostname, and port": {value: "https://example.com:1234", expect: "https://example.com:1234"},
33			"trailing slash":             {value: "example.com/", expect: "http://example.com:11434"},
34			"trailing slash port":        {value: "example.com:1234/", expect: "http://example.com:1234"},
35		}
36	
37		for k, v := range testCases {
38			t.Run(k, func(t *testing.T) {
39				t.Setenv("OLLAMA_HOST", v.value)
40	
41				client, err := ClientFromEnvironment()
42				if err != v.err {
43					t.Fatalf("expected %s, got %s", v.err, err)
44				}
45	
46				if client.base.String() != v.expect {
47					t.Fatalf("expected %s, got %s", v.expect, client.base.String())
48				}
49			})
50		}
51	}
