53	// testError represents an internal error type with status code and message
54	// this is used since the error response from the server is not a standard error struct
55	type testError struct {
56		message    string
57		statusCode int
58		raw        bool // if true, write message as-is instead of JSON encoding
59	}
60	
61	func (e testError) Error() string {
62		return e.message
63	}
