195	func TestClientDo(t *testing.T) {
196		testCases := []struct {
197			name           string
198			response       any
199			wantErr        string
200			wantStatusCode int
201		}{
202			{
203				name: "immediate error response",
204				response: testError{
205					message:    "test error message",
206					statusCode: http.StatusBadRequest,
207				},
208				wantErr:        "test error message",
209				wantStatusCode: http.StatusBadRequest,
210			},
211			{
212				name: "server error response",
213				response: testError{
214					message:    "internal error",
215					statusCode: http.StatusInternalServerError,
216				},
217				wantErr:        "internal error",
218				wantStatusCode: http.StatusInternalServerError,
219			},
220			{
221				name: "successful response",
222				response: struct {
223					ID      string `json:"id"`
224					Success bool   `json:"success"`
225				}{
226					ID:      "msg_123",
227					Success: true,
228				},
229			},
230			{
231				name: "plain text error response",
232				response: testError{
233					message:    "internal server error",
234					statusCode: http.StatusInternalServerError,
235					raw:        true,
236				},
237				wantErr:        "internal server error",
238				wantStatusCode: http.StatusInternalServerError,
239			},
240			{
241				name: "HTML error page",
242				response: testError{
243					message:    "<html><body>404 Not Found</body></html>",
244					statusCode: http.StatusNotFound,
245					raw:        true,
246				},
247				wantErr:        "<html><body>404 Not Found</body></html>",
248				wantStatusCode: http.StatusNotFound,
249			},
250		}
251	
252		for _, tc := range testCases {
253			t.Run(tc.name, func(t *testing.T) {
254				ts := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
255					if errResp, ok := tc.response.(testError); ok {
256						w.WriteHeader(errResp.statusCode)
257						if !errResp.raw {
258							err := json.NewEncoder(w).Encode(map[string]string{
259								"error": errResp.message,
260							})
261							if err != nil {
262								t.Fatal("failed to encode error response:", err)
263							}
264						} else {
265							// Write raw message (simulates non-JSON error responses)
266							fmt.Fprint(w, errResp.message)
267						}
268						return
269					}
270	
271					w.Header().Set("Content-Type", "application/json")
272					if err := json.NewEncoder(w).Encode(tc.response); err != nil {
273						t.Fatalf("failed to encode response: %v", err)
274					}
275				}))
276				defer ts.Close()
277	
278				client := NewClient(&url.URL{Scheme: "http", Host: ts.Listener.Addr().String()}, http.DefaultClient)
279	
280				var resp struct {
281					ID      string `json:"id"`
282					Success bool   `json:"success"`
283				}
284				err := client.do(t.Context(), http.MethodPost, "/v1/messages", nil, &resp)
285	
286				if tc.wantErr != "" {
287					if err == nil {
288						t.Fatalf("got nil, want error %q", tc.wantErr)
289					}
290					if err.Error() != tc.wantErr {
291						t.Errorf("error message mismatch: got %q, want %q", err.Error(), tc.wantErr)
292					}
293					if tc.wantStatusCode != 0 {
294						if statusErr, ok := err.(StatusError); ok {
295							if statusErr.StatusCode != tc.wantStatusCode {
296								t.Errorf("status code mismatch: got %d, want %d", statusErr.StatusCode, tc.wantStatusCode)
297							}
298						} else {
299							t.Errorf("expected StatusError, got %T", err)
300						}
301					}
302					return
303				}
304	
305				if err != nil {
306					t.Fatalf("got error %q, want nil", err)
307				}
308	
309				if expectedResp, ok := tc.response.(struct {
310					ID      string `json:"id"`
311					Success bool   `json:"success"`
312				}); ok {
313					if resp.ID != expectedResp.ID {
314						t.Errorf("response ID mismatch: got %q, want %q", resp.ID, expectedResp.ID)
315					}
316					if resp.Success != expectedResp.Success {
