77		// processed and stored in the cache. For example, Llava-style models should insert
78		// placeholder tokens equal to the feature size of the corresponding image with
79		// the image itself attached to and split across these tokens. When Forward is called
80		// a partial subset of these tokens may be submitted according to the batch size.
81		//
82		// This function is also responsible for updating MultimodalHash for any Multimodal
83		// that is modified to ensure that there is a unique hash value that accurately
84		// represents the contents.
85		PostTokenize([]*input.Input) ([]*input.Input, error)
86	}
