344	func isValidPart(kind partKind, s string) bool {
345		if !isValidLen(kind, s) {
346			return false
347		}
348		for i := range s {
349			if i == 0 {
350				if !isAlphanumericOrUnderscore(s[i]) {
351					return false
352				}
353				continue
354			}
355			switch s[i] {
356			case '_', '-':
357			case '.':
358				if kind == kindNamespace {
359					return false
360				}
361			case ':':
362				if kind != kindHost && kind != kindDigest {
363					return false
364				}
365			default:
366				if !isAlphanumericOrUnderscore(s[i]) {
367					return false
368				}
369			}
370		}
371		return true
372	}
