1940	// ensureServerRunning checks if the ollama server is running and starts it in the background if not.
1941	func ensureServerRunning(ctx context.Context) error {
1942		client, err := api.ClientFromEnvironment()
1943		if err != nil {
1944			return err
1945		}
1946	
1947		// Check if server is already running
1948		if err := client.Heartbeat(ctx); err == nil {
1949			return nil // server is already running
1950		}
1951	
1952		// Server not running, start it in the background
1953		exe, err := os.Executable()
1954		if err != nil {
1955			return fmt.Errorf("could not find executable: %w", err)
1956		}
1957	
1958		serverCmd := exec.CommandContext(ctx, exe, "serve")
1959		serverCmd.Env = os.Environ()
1960		serverCmd.SysProcAttr = backgroundServerSysProcAttr()
1961		if err := serverCmd.Start(); err != nil {
1962			return fmt.Errorf("failed to start server: %w", err)
1963		}
1964	
1965		// Wait for the server to be ready
1966		for {
1967			time.Sleep(500 * time.Millisecond)
1968			if err := client.Heartbeat(ctx); err == nil {
1969				return nil // server has started
1970			}
1971		}
1972	}
